INSERT INTO "CharacterRelationshipGraph" (id, "characterId", "relatedName", "relationshipType", description, "keyEpisodes", "emotionalBond") VALUES
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ロロノア・ゾロ', '仲間', 'ルフィが最初に仲間にした剣士。東の海で海軍に囚われていたゾロを解放し、共に海賊となった。船長と副船長として絶対的な信頼関係で結ばれており、ルフィの夢を誰よりも理解し支える存在。ウイスキーピークでの背中合わせの戦闘は二人の絆の象徴。', '["東の海でゾロを仲間に誘う", "ウイスキーピークでの共闘", "スリラーバークでのゾロの自己犠牲"]', '互いの夢を命懸けで守る船長と右腕'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ナミ', '仲間', 'ルフィが仲間にした航海士。アーロンパークでナミの涙を見て「当たり前だ!!」と叫び、アーロンを倒した。ルフィにとってナミは方向音痴の自分を導く不可欠な存在であり、ナミにとってルフィは人生を変えてくれた恩人。', '["アーロンパークでの救出", "ナミに麦わら帽子を預ける", "ホールケーキアイランドでの再会"]', '命を預けられる絶対的信頼'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ヴィンスモーク・サンジ', '仲間', 'バラティエで出会った料理人。サンジの夢オールブルーとルフィの海賊王の夢が交差し、仲間になった。ホールケーキアイランドでは離脱したサンジを迎えに行き、「おれは お前の作ったメシが食いてェ」と本音をぶつけた名場面は多くのファンの涙を誘った。', '["バラティエでの仲間勧誘", "ホールケーキアイランドでの対峙と和解", "ワノ国での共闘"]', 'どんな時も信じ抜く船長としての器'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ウソップ', '仲間', 'シロップ村で出会った狙撃手。臆病だが仲間思いの性格はルフィと相性が良い。ウォーターセブンでのメリー号を巡る決闘は二人の友情の深さゆえの衝突。エニエスロビーでウソップが「仲間にしてくれ」と叫んだ場面は和解の名シーン。', '["シロップ村での出会い", "ウォーターセブンでの決闘", "エニエスロビーでの和解"]', '幼馴染のような対等な友情'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'トニートニー・チョッパー', '仲間', 'ドラム島で出会った船医。人間でもトナカイでもない自分を受け入れてくれたルフィに深い感謝を持つ。ルフィはチョッパーの過去を知り「うるせェ!!! いこう!!!」と一言で仲間に迎え入れた。', '["ドラム島でワポルを倒す", "チョッパーを仲間に誘う", "エニエスロビーでの共闘"]', '無条件の受容と家族のような絆'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ニコ・ロビン', '仲間', 'アラバスタ編後に合流した考古学者。エニエスロビーでロビンが「生きたい」と叫んだ瞬間、ルフィは世界政府に宣戦布告した。この出来事はロビンの人生を根底から変え、初めて本当の居場所を見つけた瞬間となった。', '["アラバスタでの共闘後合流", "エニエスロビーでの救出劇", "ワノ国での信頼"]', '存在を全肯定する揺るがない受容'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'フランキー', '仲間', 'ウォーターセブンで出会った船大工。最初は敵対していたが、エニエスロビーでの共闘を経て仲間に。サウザンドサニー号の建造者として、一味の航海を支える。ルフィの自由な生き方にフランキーも共感している。', '["ウォーターセブンでの対立", "エニエスロビーでの共闘", "サウザンドサニー号の建造"]', '夢の船を託された信頼'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ブルック', '仲間', 'スリラーバークで出会った音楽家。50年間一人で漂流していたブルックをルフィは「仲間になれ」と即座に誘った。ブルックにとってルフィはラブーンとの約束を果たすための希望であり、再び仲間と航海できる喜びそのもの。', '["スリラーバークでの出会い", "仲間への即座の勧誘", "ホールケーキアイランドでの活躍"]', '孤独から救い出した友情'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ジンベエ', '仲間', '魚人島で正式に仲間入りした操舵手。インペルダウンとマリンフォードで共に戦い、エースを失ったルフィを支えた恩人。仁義と誇りを重んじるジンベエは、ルフィの成長を見守る兄貴分的存在。', '["インペルダウンでの共闘", "マリンフォードでの献身", "魚人島での仲間入り宣言"]', '命の恩人としての深い絆'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'シャンクス', '師弟', 'ルフィが海賊を志す原点となった赤髪海賊団の大頭。フーシャ村で幼いルフィを近海の主から身を挺して守り、左腕を失った。麦わら帽子を託し「いつか返しに来い、立派な海賊になって」と約束した。ルフィの全ての出発点。', '["フーシャ村での出会い", "近海の主からの救出と左腕喪失", "麦わら帽子の約束"]', '人生の原点となった憧れの存在'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ポートガス・D・エース', '家族', 'ルフィの義兄。幼少期にダダンの元で共に育ち、サボと三人で盃を交わした義兄弟。マリンフォードでエースを救出するも、赤犬の攻撃からルフィを庇いエースは命を落とした。ルフィの人生最大のトラウマであり、強くなる決意の原点。', '["幼少期の義兄弟の盃", "インペルダウン突入", "マリンフォードでのエースの死"]', '命より大切な義兄弟の絆'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'クロコダイル', '敵', 'アラバスタの影の支配者。バロックワークスの社長として国を乗っ取ろうとした。ルフィは二度敗北するも三度目の戦いで勝利。王下七武海としての実力は圧倒的で、ルフィにとって初めての本格的な強敵だった。', '["アラバスタでの三度の戦い", "インペルダウンでの共闘", "クロスギルド結成"]', '因縁の敵から奇妙な協力関係へ'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', '百獣のカイドウ', '敵', '四皇の一角。世界最強の生物と呼ばれる。ワノ国を支配し、ルフィは何度も敗北を重ねながらも最終的にギア5の力で打倒した。ルフィにとって四皇という壁を超えるための最大の試練だった。', '["ワノ国での初戦と敗北", "鬼ヶ島決戦", "ギア5覚醒と最終決着"]', '四皇の壁を超えた死闘の記憶'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'マーシャル・D・ティーチ', '敵', '黒ひげ。エースを海軍に引き渡し、マリンフォード戦争の引き金を作った宿敵。ヤミヤミの実とグラグラの実の二つの能力を持つ唯一の人間。ルフィの最終的な敵の一人として物語の核心に位置する。', '["ジャヤでの邂逅", "エース捕獲による因縁", "インペルダウンでの遭遇"]', '兄の死の遠因となった宿敵'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ボア・ハンコック', '恋愛対象', '九蛇海賊団船長にして王下七武海。ルフィに恋をした世界一の美女。ルフィはハンコックの過去の傷を気にせず対等に接したことで、彼女の心を開かせた。インペルダウン潜入を助けるなど、ルフィのためなら何でもする。', '["アマゾン・リリーでの出会い", "インペルダウン潜入への協力", "女ヶ島での修行期間"]', '一方的だが純粋な恋慕'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'トラファルガー・ロー', '仲間', '最悪の世代の一人。マリンフォードでルフィの命を救った外科医。パンクハザードで同盟を結び、ドフラミンゴ打倒からワノ国までの長い共闘関係を築いた。互いの実力を認め合うライバル的パートナー。', '["マリンフォードでのルフィ救出", "パンクハザードでの同盟", "ワノ国での共闘"]', '命の恩を超えた対等な同盟'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ネフェルタリ・ビビ', '仲間', 'アラバスタ王国の王女。バロックワークスに潜入し祖国を救おうとした勇敢な少女。一味と共に旅をし、アラバスタ到着後も深い絆で結ばれている。左腕の×印は永遠の仲間の証。', '["ウイスキーピークでの出会い", "アラバスタでの別れと×印", "レヴェリーでの再登場"]', '離れていても消えない仲間の印'),
(gen_random_uuid(), '6961b4d9-1b3e-4cde-97a9-0e3492a37657', 'ヤマト', '仲間', 'カイドウの子。おでんに憧れ、20年間鬼ヶ島に幽閉されていた。ルフィと共にカイドウに挑み、自由を勝ち取った。ルフィの自由な生き方に共鳴し、共に海へ出ることを望んでいた。', '["鬼ヶ島での出会い", "カイドウとの親子対決", "ワノ国での共闘"]', '自由への渇望で結ばれた同志'),

